mapper.update:
BEGIN
    EXECUTE IMMEDIATE '
        CREATE TABLE TEST_CHUNK_SOURCE (
            ID NUMBER(19,0) PRIMARY KEY,
            COL1 VARCHAR2(100),
            COL2 VARCHAR2(100),
            COL3 VARCHAR2(100),
            PROCESSED CHAR(1) DEFAULT ''N'' NOT NULL
        )';
EXCEPTION
    WHEN OTHERS THEN
        IF SQLCODE != -955 THEN
            RAISE;
        END IF;
END;

BEGIN
    EXECUTE IMMEDIATE '
        CREATE TABLE TEST_CHUNK_TARGET (
            ID NUMBER(19,0) PRIMARY KEY,
            COL1 VARCHAR2(100),
            COL2 VARCHAR2(100),
            COL3 VARCHAR2(100),
            CREATED_AT TIMESTAMP DEFAULT SYSTIMESTAMP
        )';
EXCEPTION
    WHEN OTHERS THEN
        IF SQLCODE != -955 THEN
            RAISE;
        END IF;
END;

UPDATE TEST_CHUNK_SOURCE
SET PROCESSED = 'Y'
WHERE ID = #{id}
